    65→FILE *open_dump(char type, double cur_time, uint32_t timestamp, int data_size, const char *extension)
    66→{
    67→	char *fn = malloc(strlen(out_dir) + 50);
    68→	sprintf(fn, "%c-%f-%u.%s", type, cur_time, timestamp, extension);
    69→	fprintf(index_fp, "%s\n", fn);
