    71→	FILE* fp = fopen(fn, "wb");
    72→	if (!fp) {
    73→		printf("Error: Cannot open file [%s]\n", fn);
    74→		exit(1);
    75→	}
    76→	printf("%s\n", fn);
    77→	free(fn);
    78→	return fp;
