   104→void dump(char type, uint32_t timestamp, void *data, int data_size)
   105→{
   106→	// timestamp can be at most 10 characters, we have a few extra
   107→	double cur_time = get_time();
   108→	FILE *fp;
   109→	last_timestamp = timestamp;
   110→	switch (type) {
   111→		case 'd':
   112→			fp = open_dump(type, cur_time, timestamp, data_size, "pgm");
   113→			dump_depth(fp, data, data_size);
   114→			fclose(fp);
   115→			break;
   116→		case 'r':
   117→			fp = open_dump(type, cur_time, timestamp, data_size, "ppm");
   118→			dump_rgb(fp, data, data_size);
   119→			fclose(fp);
   120→			break;
   121→		case 'a':
   122→			fp = open_dump(type, cur_time, timestamp, data_size, "dump");
   123→			fwrite(data, data_size, 1, fp);
   124→			fclose(fp);
   125→			break;
   126→	}
   127→}
