   129→void dump_ffmpeg_24(FILE *stream, uint32_t timestamp, void *data,
   130→					int data_size)
   131→{
   132→	fwrite(data, data_size, 1, stream);
   133→}
   134→
   135→void dump_ffmpeg_pad16(FILE *stream, uint32_t timestamp, void *data,
   136→					   int data_size)
   137→{
   138→	unsigned int z = 0;
   139→	uint16_t* data_ptr = (uint16_t*)data;
   140→	uint16_t* end = data_ptr + data_size;
   141→	while (data_ptr < end) {
   142→		z = *data_ptr;
   143→		fwrite(((char*)(&z)), 3, 1, stream);
   144→		data_ptr += 2;
   145→	}
   146→}
