    97→static char *one_line(FILE *fp)
    98→{
    99→	int c;
   100→	int pos = 0;
   101→	char *out = NULL;
   102→	for (c = fgetc(fp); !(c == '\n' || c == EOF); c = fgetc(fp))
   103→	{
   104→		out = realloc(out, pos + 1);
   105→		out[pos++] = c;
   106→	}
   107→	if (out) {
   108→		out = realloc(out, pos + 1);
   109→		out[pos] = '\0';
   110→	}
   111→	return out;
   112→}
   113→
   114→static int get_data_size(FILE *fp)
   115→{
   116→	int orig = ftell(fp);
   117→	fseek(fp, 0L, SEEK_END);
   118→	int out = ftell(fp);
   119→	fseek(fp, orig, SEEK_SET);
   120→	return out;
   121→}
   122→
   123→static int parse_line(char *type, double *cur_time, unsigned int *timestamp, unsigned int *data_size, char **data)
   124→{
   125→	char *line = one_line(index_fp);
   126→	if (!line) {
   127→		printf("Warning: No more lines in [%s]\n", input_path);
   128→		return -1;
   129→	}
   130→	int file_path_size = strlen(input_path) + strlen(line) + 50;
   131→	char *file_path = malloc(file_path_size);
   132→	snprintf(file_path, file_path_size, "%s/%s", input_path, line);
   133→	// Open file
   134→	FILE *cur_fp = fopen(file_path, "rb");
   135→	if (!cur_fp) {
   136→		printf("Error: Cannot open file [%s]\n", file_path);
   137→		exit(1);
   138→	}
   139→	// Parse data from file name
   140→	int ret = 0;
   141→	*data_size = get_data_size(cur_fp);
   142→	sscanf(line, "%c-%lf-%u-%*s", type, cur_time, timestamp);
   143→	*data = malloc(*data_size);
   144→	if (fread(*data, *data_size, 1, cur_fp) != 1) {
   145→		printf("Error: Couldn't read entire file.\n");
   146→		ret = -1;
   147→	}
   148→	fclose(cur_fp);
   149→	free(line);
   150→	free(file_path);
   151→	return ret;
   152→}
   153→
   154→static void open_index()
   155→{
   156→	int index_path_size = strlen(input_path) + 50;
   157→	char *index_path = malloc(index_path_size);
   158→	snprintf(index_path, index_path_size, "%s/INDEX.txt", input_path);
   159→	index_fp = fopen(index_path, "rb");
   160→	if (!index_fp) {
   161→		printf("Error: Cannot open file [%s]\n", index_path);
   162→		exit(1);
   163→	}
   164→	free(index_path);
   165→}
   166→
   167→static void close_index()
   168→{
   169→	fclose(index_fp);
   170→	index_fp = NULL;
   171→	record_prev_time = 0;
   172→	playback_prev_time = 0;
   173→}
