   212→int freenect_process_events(freenect_context *ctx)
   213→{
   214→	/* This is where the magic happens. We read 1 update from the index
   215→	   per call, so this needs to be called in a loop like usual.  If the
   216→	   index line is a Depth/RGB image the provided callback is called.  If
   217→	   the index line is accelerometer data, then it is used to update our
   218→	   internal state.  If you query for the accelerometer data you get the
   219→	   last sensor reading that we have.  The time delays are compensated as
   220→	   best as we can to match those from the original data and current run
   221→	   conditions (e.g., if it takes longer to run this code then we wait less).
   222→	 */
   223→	if (!index_fp)
   224→		open_index();
   225→	char type;
   226→	double record_cur_time;
   227→	unsigned int timestamp, data_size;
   228→	char *data = NULL;
   229→	if (parse_line(&type, &record_cur_time, &timestamp, &data_size, &data)) {
   230→                if (loop_playback) {
   231→			close_index();
   232→			return 0;
   233→                } else
   234→		    return -1;
   235→	}
   236→	// Sleep an amount that compensates for the original and current delays
   237→	// playback_ is w.r.t. the current time
   238→	// record_ is w.r.t. the original time period during the recording
   239→	if (record_prev_time != 0. && playback_prev_time != 0.)
   240→		sleep_highres((record_cur_time - record_prev_time) - (get_time() - playback_prev_time));
   241→	record_prev_time = record_cur_time;
   242→	switch (type) {
   243→		case 'd':
   244→			if (cur_depth_cb && depth_running) {
   245→				freenect_frame_mode mode = freenect_get_current_depth_mode(fake_dev);
   246→				void *cur_depth = skip_line(data);
   247→				void *depth_buffer = user_depth_buf ? user_depth_buf : default_depth_back;
   248→
   249→				switch (mode.depth_format) {
   250→				case FREENECT_DEPTH_11BIT:
   251→				    memcpy(depth_buffer, cur_depth, mode.bytes);
   252→				    break;
   253→                                case FREENECT_DEPTH_REGISTERED:
   254→                                    freenect_apply_registration(fake_dev, cur_depth, depth_buffer, true);
   255→                                    break;
   256→				case FREENECT_DEPTH_MM:
   257→				    freenect_apply_depth_unpacked_to_mm(fake_dev, cur_depth, depth_buffer);
   258→				    break;
   259→				default:
   260→				    assert(0);
   261→				    break;
   262→				}
   263→
   264→				cur_depth_cb(fake_dev, depth_buffer, timestamp);
   265→			}
   266→			break;
   267→		case 'r':
   268→			if (cur_video_cb && rgb_running) {
   269→				void *cur_video = skip_line(data);
   270→				void *video_buffer = user_video_buf ? user_video_buf : default_video_back;
   271→
   272→				freenect_frame_mode mode = freenect_get_current_video_mode(fake_dev);
   273→
   274→				switch (mode.video_format) {
   275→				case FREENECT_VIDEO_RGB:
   276→					memcpy(video_buffer, cur_video, mode.bytes);
   277→					break;
   278→				case FREENECT_VIDEO_YUV_RAW:
   279→					convert_rgb_to_uyvy(cur_video, video_buffer, mode);
   280→					break;
   281→				default:
   282→					assert(0);
   283→					break;
   284→				}
   285→
   286→				cur_video_cb(fake_dev, video_buffer, timestamp);
   287→			}
   288→			break;
   289→		case 'a':
   290→			if (data_size == sizeof(state)) {
   291→				memcpy(&state, data, sizeof(state));
   292→			} else if (!already_warned) {
   293→				already_warned = 1;
   294→				printf("\n\nWarning: Accelerometer data has an unexpected"
   295→				       " size [%u] instead of [%u].  The acceleration "
   296→				       "and tilt data will be substituted for dummy "
   297→				       "values.  This data was probably made with an "
   298→				       "older version of record (the upstream interface "
   299→				       "changed).\n\n",
   300→				       data_size, (unsigned int)sizeof state);
   301→			}
   302→			break;
   303→	}
   304→	free(data);
   305→	playback_prev_time = get_time();
   306→	return 0;
   307→}
